module RefModule(clk, rst, start, operation, state);  
    input clk;  
    input rst;  
    input start;  
    input operation;  
    output reg [1:0] state;  

    parameter IDLE = 2'b00, READ = 2'b01, WRITE = 2'b10;  

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin  
        if (rst)  
            state <= IDLE;  
        else begin  
            case (state)  
                IDLE: if (start)  
                          state <= (operation) ? WRITE : READ;  
                READ: state <= IDLE;  
                WRITE: state <= IDLE;  
                default: state <= IDLE;  
            endcase  
        end  
    end  
endmodule
